class Solution {
public:
    int palindromePartition(string s, int k) {
        int n = s.size();
        vector<vector<int>> dp(n + 1, vector<int>(k + 1, INT_MAX));
        dp[0][0] = 0;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= min(i, k); j++) {
                for (int l = 0; l < i; l++) {
                    int changes = 0;
                    string substr = s.substr(l, i - l);
                    for (int p = 0; p < substr.size() / 2; p++) {
                        if (substr[p] != substr[substr.size() - 1 - p]) changes++;
                    }
                    dp[i][j] = min(dp[i][j], dp[l][j - 1] + changes);
                }
            }
        }
        return dp[n][k];
    }
};
